Rule.Source:
  import sailpoint.object.Identity;
  import sailpoint.object.Custom;
  import sailpoint.tools.Util;
  import sailpoint.api.SailPointContext;
  import sailpoint.api.IdentityService;
  import sailpoint.object.Application;
  import org.apache.commons.logging.Log;
  import org.apache.commons.logging.LogFactory;

  Log logger = LogFactory.getLog("rule.Ascension.Rule.AD.Field.sAMAccountName");
  /**
	 * Check nativeidentity for user account creation
	 * @param identity the identity
	 * @return sAMName distinguishedName
	 */

  logger.debug("Entering AD sAMAccountName field");
  String sAMName= null;
  String tempName= null;
  boolean existsInAD = false;
  boolean hasEnabledAD = false;
  IdentityService idSvc = new IdentityService(context);
  Application application = context.getObjectByName(Application.class, "DB-Peoplesoft-HCM-Primary");
  
  List appList = new ArrayList();
  appList.add(application);

  if(null != identity){

    if(Util.nullSafeCaseInsensitiveEq(identity.getStringAttribute("manualTerm"),"No")){
      tempName = checkExistingSamAccName(identity);
    }

    if(Util.isNullOrEmpty(tempName)){
      if(checkIfUserNameNeedsToBeChanged(identity.getName())){
        tempName = identity.getName();
      }
      else if(idSvc.hasAccounts(identity,appList)){
        tempName = identity.getAttribute("samAccountName");
      }  
    }


    if(Util.isNotNullOrEmpty(tempName)){
      existsInAD = checkDuplicatesAMAccountName(tempName);
      if(!existsInAD){
        sAMName = tempName;
      }
      else{
        sAMName = generateUserName(identity.getFirstname(), identity.getLastname());
      }
    }
    else{
      sAMName = generateUserName(identity.getFirstname(), identity.getLastname());
    }


    Identity identity = context.getObjectByName(Identity.class,identity.getName());  

    if(Util.nullSafeCaseInsensitiveEq("AMITA",identity.getAttribute("domain"))){
      Application app = context.getObjectByName(Application.class,"AD-AMITA");
      if(null != app){

        List refLinks = idSvc.getLinks(identity, app, null);
        if(refLinks!=null && !refLinks.isEmpty())
        {

          for(Link adLink: refLinks)
          {
            if(null!=adLink && !adLink.isDisabled())
            {
              hasEnabledAD = true;
              break;
            }
          }
        }
        if(!hasEnabledAD && Util.isNullOrEmpty(identity.getAttribute("initialOperId"))){
          identity.setAttribute("initialOperId",sAMName);
          context.saveObject(identity);
          context.commitTransaction();   
        }
      }
    }else {

      QueryOptions ops = new QueryOptions();
      ops.addFilter(Filter.eq("type", "Active Directory - Direct"));
      List adApps = context.getObjects(Application.class, ops);

      if(null!=identity)
      {
        //Get All AD Links on Identity
        List refLinks = idSvc.getLinks(identity, adApps, null);
        if(refLinks!=null && !refLinks.isEmpty())
        {

          for(Link adLink: refLinks)
          {
            if(null!=adLink && !adLink.isDisabled())
            {
              hasEnabledAD = true;
              break;
            }
          }
        }
        if(!hasEnabledAD && Util.isNullOrEmpty(identity.getAttribute("initialOperId"))){
          identity.setAttribute("initialOperId",sAMName);
          context.saveObject(identity);
          context.commitTransaction();  
        }
      }

    }
  }

  logger.debug("Exiting AD sAMAccountName field");
  return sAMName;
